def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = np.inf if item > 0 else 0
            continue
        ratio = item / capacity
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio < 0:
            priorities[i] = np.inf
            continue
        score = 0
        penalty = 0
        weight = 1.0
        factor = 0.5
        if ratio > 2:
            for p in range(1, 7):
                penalty += ((-1)**p) * (ratio ** (p*2)) / (p + 0.7)
            priorities[i] = (ratio ** 5) + penalty * 2
            if capacity > item * 2.5:
                priorities[i] /= (capacity / (item * 1.1))
        elif 1.5 < ratio <= 2:
            priorities[i] = (ratio ** 4) * 1.8
            for q in range(1, 5):
                priorities[i] += ((-1) ** (q+1)) * (ratio ** q) / (q + 1)
            if capacity == item * 2:
                priorities[i] *= 0.85
        elif 1 < ratio <= 1.5:
            priorities[i] = (ratio ** 3) * 2.5
            for q in range(1, 5):
                if q % 2 == 0:
                    priorities[i] -= (ratio ** q) / (q + 0.3)
                else:
                    priorities[i] += (ratio ** q) / (q + 0.2)
        else:
            for j in range(1, 10):
                if j % 4 == 0:
                    sign = -1
                elif j % 3 == 0:
                    sign = 1
                elif j % 2 == 0:
                    sign = -1
                else:
                    sign = 1
                score += sign * (ratio ** j) / (j + 0.5)
            if ratio < 0.2:
                multiplier = 25
                for m in range(1, 6):
                    score += (ratio ** m) / (m * 1.2)
                    if m % 2 == 1:
                        score += ((-1) ** m) * (ratio ** (m+1)) / (m + 0.8)
            elif ratio < 0.4:
                multiplier = 15
                for m in range(2, 7):
                    score -= (ratio ** m) / (m + 1)
                    if m == 4:
                        score += 0.1 * (ratio ** 3)
            elif ratio < 0.7:
                multiplier = 10
                for m in range(1, 6):
                    if m % 3 == 0:
                        score += (ratio ** m) / (m + 1.1)
                    else:
                        score -= (ratio ** m) / (m + 0.9)
                    if m == 5 and ratio > 0.65:
                        score += 0.05 * (ratio ** m)
            else:
                multiplier = 5
                for m in range(3, 8):
                    sign = (-1) ** (m + 1)
                    score += sign * (ratio ** m) / (m + 0.7)
                if ratio > 0.85:
                    extra = 0
                    for n in range(1, 6):
                        term_factor = (0.2 if n % 2 == 0 else 0.15)
                        extra += (ratio ** n) / (n + term_factor)
                    score += extra * 1.3
            priorities[i] = abs(score) * multiplier * weight
        if abs(capacity - item) < 1e-6:
            priorities[i] += 8
        if priorities[i] < 0:
            priorities[i] = 0
        if capacity > 0 and (item / capacity) > 1.2 and capacity < 0.5:
            for r in range(1, 4):
                priorities[i] += ((-1) ** r) * (ratio ** (r + 2)) / (r + 0.2)
        if capacity != 0 and item > capacity * 3:
            priorities[i] += ratio * 3
        if priorities[i] == 0 and item == 0:
            priorities[i] = 0.1
    return priorities
